"use client";

/**
 * @file Home page for Moon's Once UI Next user app.
 */

import Link from "next/link";
import {Button, Flex} from "@once-ui-system/core";
import {useMoonJson} from "../../lib/api.js";
import {buildReaderPath, buildTitlePath} from "../../lib/routes.js";
import {formatProgress} from "../../lib/date.js";
import TitleCard from "../TitleCard.jsx";
import {EmptyView, ErrorView, LoadingView} from "../StateView.jsx";

const toContinueLink = (entry) => {
  const bookmark = entry?.bookmark || {};
  if (!bookmark.chapterId) {
    return buildTitlePath(entry?.libraryTypeSlug || entry?.mediaType || "manga", entry?.titleId || entry?.mediaId || "");
  }
  return buildReaderPath(
    entry?.libraryTypeSlug || entry?.mediaType || "manga",
    entry?.titleId || entry?.mediaId || "",
    bookmark.chapterId
  );
};

/**
 * Render Moon's new home surface.
 *
 * @returns {import("react").ReactNode}
 */
export const HomePageClient = () => {
  const {loading, error, data} = useMoonJson("/api/moon-v3/user/home", {
    fallback: {
      latestTitles: [],
      continueReading: [],
      requests: [],
      following: []
    }
  });

  if (loading) {
    return <LoadingView label="Moon is building your home shelf, continue-reading stack, and request queue." />;
  }

  if (error) {
    return <ErrorView detail={error} />;
  }

  const featured = data?.continueReading?.[0] || data?.latestTitles?.[0] || null;

  return (
    <div className="moon-page-grid">
      <section className="moon-panel moon-hero">
        <div className="moon-hero-copy">
          <span className="moon-kicker">Reader</span>
          <h1 className="moon-surface-heading">{featured?.title || "Full-page Moon reading"}</h1>
          <p className="moon-support-copy">
            Kavita-inspired browsing, richer source metadata, and seamless reading now live in the same Moon workspace.
          </p>
          <Flex gap="12" wrap>
            {featured ? (
              <Button href={toContinueLink(featured)} variant="primary" size="l">
                {data?.continueReading?.length ? "Continue reading" : "Open title"}
              </Button>
            ) : null}
            <Button href="/browse" variant="secondary" size="l">
              Browse library
            </Button>
          </Flex>
        </div>
        <div className="moon-panel moon-section">
          <div className="moon-section-head">
            <div>
              <span className="moon-kicker">Queue</span>
              <h2>Your live overview</h2>
            </div>
          </div>
          <div className="moon-list">
            {(data?.continueReading || []).slice(0, 3).map((entry) => (
              <Link key={`${entry.titleId}:${entry.bookmark?.chapterId || "title"}`} href={toContinueLink(entry)} className="moon-list-row">
                <div>
                  <strong>{entry.title}</strong>
                  <div className="moon-muted">{entry.chapterLabel || entry.latestChapter || "Keep reading"}</div>
                </div>
                <div className="moon-muted">{formatProgress(entry.positionRatio || 0)}</div>
              </Link>
            ))}
            {(data?.requests || []).slice(0, 3).map((entry) => (
              <div key={entry.id} className="moon-list-row">
                <div>
                  <strong>{entry.title}</strong>
                  <div className="moon-muted">{entry.notes || "Moon request"}</div>
                </div>
                <div className="moon-muted">{entry.status}</div>
              </div>
            ))}
            {!(data?.continueReading?.length || data?.requests?.length) ? (
              <EmptyView
                title="Nothing is waiting yet"
                detail="Start reading, follow a title, or request something from Moon to populate this surface."
              />
            ) : null}
          </div>
        </div>
      </section>

      <section className="moon-panel moon-section">
        <div className="moon-section-head">
          <div>
            <span className="moon-kicker">Continue</span>
            <h2>Pick back up instantly</h2>
          </div>
        </div>
        {data?.continueReading?.length ? (
          <div className="moon-card-row">
            {data.continueReading.slice(0, 6).map((entry) => (
              <TitleCard
                key={`${entry.titleId}:${entry.bookmark?.chapterId || "chapter"}`}
                title={{
                  id: entry.titleId,
                  title: entry.title,
                  summary: entry.summary,
                  mediaType: entry.mediaType,
                  libraryTypeLabel: entry.libraryTypeLabel,
                  libraryTypeSlug: entry.libraryTypeSlug,
                  latestChapter: entry.chapterLabel || entry.latestChapter,
                  coverUrl: entry.coverUrl
                }}
                compact
              />
            ))}
          </div>
        ) : (
          <EmptyView title="No progress yet" detail="Open any chapter and Moon will remember exactly where to bring you back." />
        )}
      </section>

      <section className="moon-panel moon-section">
        <div className="moon-section-head">
          <div>
            <span className="moon-kicker">Library</span>
            <h2>Fresh titles</h2>
          </div>
        </div>
        {data?.latestTitles?.length ? (
          <div className="moon-card-row">
            {data.latestTitles.slice(0, 8).map((title) => (
              <TitleCard key={title.id} title={title} />
            ))}
          </div>
        ) : (
          <EmptyView title="Library is still empty" detail="Once Raven imports real titles, Moon will surface them here." />
        )}
      </section>
    </div>
  );
};

export default HomePageClient;
